const fs=require('fs'),path=require('path');
const workDir='/home/node/facturas/work',adjDir=path.join(workDir,'adj');
const ocMap={},diagnostics=[];
function readCodigoObra(p){try{const f=p.replace(/\.pdf$/i,'.obra');if(fs.existsSync(f)){const r=fs.readFileSync(f,'utf8').trim();if(r)return r.replace(/^0+/,'')||r;}}catch(e){}return null;}
const obraMap={};
try{if(fs.existsSync(adjDir))fs.readdirSync(adjDir).filter(f=>f.toLowerCase().endsWith('.pdf')).forEach(af=>{const c=readCodigoObra(path.join(adjDir,af));if(c)obraMap[af]=c;});}catch(e){}
const adjFileMap={};
try{if(fs.existsSync(adjDir))fs.readdirSync(adjDir).filter(f=>f.startsWith('__adj__')&&f.toLowerCase().endsWith('.pdf')).forEach(af=>{const wp=af.slice(7),si=wp.lastIndexOf('__');if(si===-1)return;const parent=wp.slice(0,si)+'.pdf',adjName=wp.slice(si+2);if(!adjFileMap[parent])adjFileMap[parent]=[];adjFileMap[parent].push({adjFile:af,adjName});});}catch(e){}
try{const filesInDir=new Set(fs.readdirSync(workDir).filter(f=>f.toLowerCase().endsWith('.pdf')));
for(const file of new Set([...filesInDir,...Object.keys(adjFileMap)])){
  const adjEntries=adjFileMap[file]||[],ocEntries=[],filenames=adjEntries.map(e=>e.adjName);
  for(const{adjFile,adjName}of adjEntries){if(/remito/i.test(adjName))continue;for(const num of(adjName.match(/\d{4,}/g)||[])){const clean=num.replace(/^0+/,'')||num;if(!ocEntries.find(e=>e.numero_oc===clean))ocEntries.push({numero_oc:clean,nombre_adjunto:adjName,codigo_obra:obraMap[adjFile]||null});}}
  if(ocEntries.length>0)ocMap[file]=ocEntries;
  diagnostics.push({file,attachment_filenames:filenames,oc_entries:ocEntries,error:null});
}}catch(e){return[{json:{stdout:'{}',error:e.message,diagnostics:[]}}];}
return[{json:{stdout:JSON.stringify(ocMap),oc_map:ocMap,obra_map:obraMap,diagnostics,total_pdfs:diagnostics.length,pdfs_with_oc:Object.keys(ocMap).length}}];

