const ocMap = $items("Leer OC Map")?.[0]?.json?.oc_map || {};
const inputOcEntries = $items("Set Campos de Entrada")?.[0]?.json?.oc_entries || [];

function resolveOcEntries(fn) {
  if (!fn) return [];
  const base = fn.split('/').pop().split('\\').pop();
  return ocMap[fn]
    || ocMap[base]
    || ocMap[base.replace(/\.[^.]+$/, '') + '.pdf']
    || ocMap[base.replace(/\.[^.]+$/, '')]
    || ocMap[fn.replace(/\.[^.]+$/, '') + '.pdf']
    || ocMap[fn.replace(/\.[^.]+$/, '')]
    || [];
}

return $input.all().map(item => {
  const fn = item.json.fileName || '';
  const fromDisk = resolveOcEntries(fn);
  // Si pdfdetach extrajo adjuntos del disco, usarlos. Si no, usar oc_entries del Worker.
  const raw = fromDisk.length > 0 ? fromDisk : inputOcEntries;
  return {
    json: {
      ...item.json,
      oc_map: ocMap,
      oc_entries_pre: Array.isArray(raw) ? raw : (raw ? [raw] : []),
      source_file_resolved: (fn.split('/').pop().split('\\').pop()) || null,
    }
  };
});

