const items    = $input.all();
const results  = [];
const ocrItems = $items("Loop Over Items");
const ocMap    = ocrItems?.[0]?.json?.oc_map || {};
const jobId    = $items("Set Campos de Entrada")?.[0]?.json?.job_id ?? null;

// Hash SHA-256 simple en Node.js (disponible en n8n)
function sha256(str) {
  try {
    const crypto = require('crypto');
    return crypto.createHash('sha256').update(str || '').digest('hex');
  } catch (e) {
    return null;
  }
}

// Parseo robusto de fecha DD-MM-YYYY → YYYY-MM-DD para PostgreSQL
// (la IA devuelve DD-MM-YYYY según el prompt)
function parseFecha(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  // Ya en formato ISO
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  // DD-MM-YYYY (formato del prompt)
  if (/^\d{2}-\d{2}-\d{4}$/.test(s)) {
    const [d, m, y] = s.split('-');
    return `${y}-${m}-${d}`;
  }
  // DD/MM/YYYY
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) {
    const [d, m, y] = s.split('/');
    return `${y}-${m}-${d}`;
  }
  return null; // formato desconocido → null en lugar de corromper
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  let text = item.json.output ?? item.json.text ?? "";
  text = String(text).trim();

  const match = text.match(/{[\s\S]*}/);
  if (!match) continue;

  let parsed;
  try {
    parsed = JSON.parse(match[0]);
  } catch (e) {
    continue;
  }

  // Confidence normalizada a 0..1
  let confidence = parsed.confidence_score ?? null;
  if (confidence !== null) {
    confidence = Number(confidence);
    if (Number.isNaN(confidence)) confidence = null;
    else confidence = Math.max(0, Math.min(1, confidence));
  }

  const rawText    = ocrItems?.[i]?.json?.text ?? null;
  const sourceFile = ocrItems?.[i]?.json?.source_file_resolved || ocrItems?.[0]?.json?.source_file_resolved || ocrItems?.[i]?.json?.fileName || null;

  // === OC logic (idéntica a versión anterior) ===
  const tipoDoc = parsed.tipo_documento || '';

  let ordenCompra = null;
  let ocArray     = [];

  if (/^FACTURA_/.test(tipoDoc)) {
    const preResolved = ocrItems?.[i]?.json?.oc_entries_pre || ocrItems?.[0]?.json?.oc_entries_pre || [];
    const fromMap = Array.isArray(preResolved) ? preResolved.filter(Boolean) : (preResolved ? [preResolved] : []);
    const rawLLM  = parsed.orden_compra;
    const fromLLM = Array.isArray(rawLLM) ? rawLLM.filter(Boolean) : (rawLLM ? [String(rawLLM)] : []);
    const merged  = [...fromMap];
    for (const llmOC of fromLLM) {
      const s = String(llmOC);
      if (!merged.find(e => (typeof e === 'string' ? e : e.numero_oc) === s)) merged.push(llmOC);
    }
    ocArray     = merged;
    ordenCompra = (typeof ocArray[0] === 'string' ? ocArray[0] : ocArray[0]?.numero_oc) || null;
  } else if (/^(ORDEN_COMPRA|SOLICITUD_COTIZACION)/.test(tipoDoc) && parsed.numero_comprobante) {
    ordenCompra = parsed.numero_comprobante;
    ocArray     = [parsed.numero_comprobante];
  }

  results.push({
    json: {
      // --- Trazabilidad ---
      job_id:        jobId,
      source_file:   sourceFile,                   // ← NUEVO: nombre del PDF
      document_hash: sha256(rawText),              // ← NUEVO: hash para deduplicación
      raw_ocr_text:  rawText,
      ai_raw_json:   parsed,                       // ← NUEVO: JSON completo de la IA

      // --- Datos extraídos por la IA ---
      fecha:                      parseFecha(parsed.fecha),  // ← mejorado: robusto
      moneda:                     parsed.moneda ?? null,
      es_moneda_ars:              parsed.es_moneda_ars ?? null,
      es_moneda_usd:              parsed.es_moneda_usd ?? null,

      tipo_documento:             parsed.tipo_documento ?? null,
      numero_comprobante:         parsed.numero_comprobante ?? null,

      emisor_nombre:              parsed.emisor_nombre ?? null,
      emisor_cuit:                parsed.emisor_cuit ?? null,

      receptor_nombre:            parsed.receptor_nombre ?? null,
      receptor_cuit:              parsed.receptor_cuit ?? null,

      cliente:                    parsed.cliente ?? null,    // ← NUEVO: ya no se pierde

      neto_gravado:               parsed.neto_gravado ?? null,
      iva:                        parsed.iva ?? null,
      total:                      parsed.total ?? null,

      percepcion_ingresos_brutos: parsed.percepcion_ingresos_brutos ?? null,
      percepcion_iva:             parsed.percepcion_iva ?? null,

      documento_relacionado:      parsed.documento_relacionado ?? null,

      orden_compra:               ordenCompra,
      oc_array:                   ocArray,


      // --- Campos fiscales extendidos ---
      codigo_afip:               parsed.codigo_afip ?? null,
      punto_venta:               parsed.punto_venta ?? null,
      condicion_iva_emisor:      parsed.condicion_iva_emisor ?? null,
      condicion_iva_receptor:    parsed.condicion_iva_receptor ?? null,
      monto_exento:              parsed.monto_exento ?? null,
      iva_21:                    parsed.iva_21 ?? null,
      iva_105:                   parsed.iva_105 ?? null,
      iva_27:                    parsed.iva_27 ?? null,
      iva_5:                     parsed.iva_5 ?? null,
      iva_25:                    parsed.iva_25 ?? null,
      impuestos_internos:        parsed.impuestos_internos ?? null,
      nro_cae:                   parsed.nro_cae ? String(parsed.nro_cae) : null,
      fecha_vto_cae:             parseFecha(parsed.fecha_vto_cae),
      confidence_score:           confidence,
      incompleto: !!(parsed.tipo_documento && !parsed.total && !parsed.numero_comprobante), // ← NUEVO
    }
  });
}

return results;

