const items = $input.all();
const adjItems = $("Adjuntar Job a filas").all();
const result = [];

// ── Reverse lookup: numero_oc → { nombre_adjunto, codigo_obra } ─────────────
// Permite recuperar codigo_obra/nombre_adjunto incluso cuando oc_entries_pre
// llegó vacío (fileName no disponible en Inyectar OC Map) y los OCs en
// oc_array son strings planos provenientes del LLM.
const ocByNum = {};
try {
  const rawOcMap = $items("Leer OC Map")?.[0]?.json?.oc_map || {};
  for (const entries of Object.values(rawOcMap)) {
    if (!Array.isArray(entries)) continue;
    for (const entry of entries) {
      if (entry && entry.numero_oc && !ocByNum[entry.numero_oc]) {
        ocByNum[entry.numero_oc] = {
          nombre_adjunto: entry.nombre_adjunto || null,
          codigo_obra:    entry.codigo_obra    || null,
        };
      }
    }
  }
} catch(e) {}

for (const item of items) {
  const rowId = item.json.id;
  if (!rowId) continue;

  const tipoDoc = item.json.tipo_documento || '';
  if (!/^FACTURA_/.test(tipoDoc)) continue;

  const jobId = String(item.json.job_id || '');
  const numComp = String(item.json.numero_comprobante || '');

  const adjItem = adjItems.find(a =>
    String(a.json.job_id || '') === jobId &&
    String(a.json.numero_comprobante || '') === numComp
  );

  let ocArray = adjItem?.json?.oc_array || [];
  if (!Array.isArray(ocArray)) ocArray = ocArray ? [ocArray] : [];

  for (const oc of ocArray) {
    // Soporte ambos formatos: string legacy o objeto { numero_oc, nombre_adjunto, codigo_obra }
    let numero_oc, nombre_adjunto, codigo_obra;

    if (typeof oc === 'string') {
      numero_oc = oc.trim();
      // Backfill desde oc_map cuando oc_entries_pre llegó vacío
      const lookup = ocByNum[numero_oc] || {};
      nombre_adjunto = lookup.nombre_adjunto || null;
      codigo_obra    = lookup.codigo_obra    || null;
    } else if (oc && typeof oc === 'object') {
      numero_oc = String(oc.numero_oc || '').trim();
      nombre_adjunto = oc.nombre_adjunto || null;
      codigo_obra    = oc.codigo_obra    || null;
      // Backfill si faltan campos en el objeto
      if (!codigo_obra || !nombre_adjunto) {
        const lookup = ocByNum[numero_oc] || {};
        nombre_adjunto = nombre_adjunto || lookup.nombre_adjunto || null;
        codigo_obra    = codigo_obra    || lookup.codigo_obra    || null;
      }
    } else {
      continue;
    }

    if (numero_oc) {
      result.push({ json: { row_id: rowId, numero_oc, nombre_adjunto, codigo_obra } });
    }
  }
}

return result;

// ─── PF6-FIX + LOGGING (TASK-4) ───────────────────────────────────────────
const item = $input.first();
let jobId = item.json?.job_id;
if (!jobId) {
  try { jobId = $('Set Campos de Entrada').first().json?.job_id; } catch(e) {}
}
const sourceFile = item.json?.source_file || item.json?.fileName || 'desconocido';
const errMsg = item.json?.message || item.json?.error?.message
  || item.json?.description || 'Error no especificado';

console.error(`[PF6-FIX] ⚠️ Doc error IGNORADO (job sigue). job=${jobId} | file=${sourceFile} | err=${errMsg}`);

// LOG best-effort a workflow_logs
try {
  const creds = await this.getCredentials('supabaseApi');
  const url = creds.host;
  const key = creds.serviceRole || creds.apiKey;

  const jRes = await fetch(`${url}/rest/v1/pdf_jobs?id=eq.${encodeURIComponent(jobId)}&select=organization_id&limit=1`,
    { headers: { 'apikey': key, 'Authorization': `Bearer ${key}` } });
  const jData = await jRes.json();
  const orgId = Array.isArray(jData) ? jData[0]?.organization_id : null;

  await fetch(`${url}/rest/v1/workflow_logs`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'apikey': key,
      'Authorization': `Bearer ${key}`,
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      job_id: jobId,
      organization_id: orgId,
      event: 'job.doc_error',
      metadata: { source: 'n8n', source_file: sourceFile },
      error: errMsg
    })
  });
  console.log(`[LOG] job.doc_error | job=${jobId} | file=${sourceFile}`);
} catch(e) {
  console.warn('[LOG] Error al loguear job.doc_error:', e.message);
}

return [{ json: {
  job_id: jobId ?? null,
  source_file: sourceFile,
  _doc_error: true,
  _error_msg: errMsg,
  _pf6_fix: true
} }];
